+    // ── build_request_bytes ────────────────────────────────────────────
+    #[test]
+    fn build_request_bytes_get() {
+        let parsed = ParsedUrl::parse("http://example.com/api/test").unwrap();
+        let bytes = build_request_bytes(Method::Get, &parsed, "test-agent", &[], &[]);
