+    // ── Buffer ─────────────────────────────────────────────────────────
+    #[test]
+    fn buffer_new_empty() {
+        let buf = Buffer::new(Vec::new());
+        assert!(buf.is_empty());
+        assert_eq!(buf.len(), 0);
