+    #[test]
+    fn buffer_consume_partial() {
+        let mut buf = Buffer::new(vec![1, 2, 3, 4, 5]);
+        buf.consume(2);
+        assert_eq!(buf.len(), 3);
+        assert_eq!(buf.available(), &[3, 4, 5]);
